import json
from jose import jwt

def decode_and_verify_jwt(token):
    # Decode the JWT token
    decoded_token = jwt.decode(token, algorithms=["HS256"])
    
    # Verify the token signature
    try:
        jwt.verify(decoded_token, key="your-secret-key", algorithms=["HS256"])
    except jwt.InvalidTokenError as e:
        print("Invalid JWT token:", str(e))
        return None
    
    # Return the decoded and verified token
    return decoded_token